/*! ABI of the Random Number Test Application */

use linera_sdk::linera_base_types::{ContractAbi, ServiceAbi};
use serde::{Deserialize, Serialize};

pub struct RandomNumberAbi;

impl ContractAbi for RandomNumberAbi {
    type Operation = ();
    type Response = ();
}

/// Query to the random number service.
#[derive(Debug, Deserialize, Serialize)]
pub enum Query {
    /// Returns the random seeds generated by the contract.
    GetSeeds,
    /// Generates a random number from the service side.
    ServiceRandom,
}

/// Response from the random number service.
#[derive(Debug, Deserialize, Serialize)]
pub enum QueryResponse {
    /// The two seeds stored by the contract.
    Seeds { seed1: u64, seed2: u64 },
    /// Two random numbers generated by the service.
    ServiceSeeds { seed1: u64, seed2: u64 },
}

impl ServiceAbi for RandomNumberAbi {
    type Query = Query;
    type QueryResponse = QueryResponse;
}
